const aiResponse = $input.item.json;
const postText = aiResponse.choices?.[0]?.message?.content?.trim() || $input.item.json.title || 'Noticia cruceros';

const prev = $('Hay Noticias').item.json;
const groups = prev.groups || '';
const page   = prev.page   || '';
const url    = prev.link   || '';
const company = prev.company || 'general';

return [{ json: {
  postText,
  url,
  groups: groups ? groups.split(',').map(g => g.trim()).filter(Boolean) : [],
  page,
  company
} }];

